let line = String(msg.payload).trim();
if (!line) return null;

let parts = line.split(",");

if (parts.length < 2) return null;

msg.raw = line;
msg.time = parts[0];      // keep as text
msg.type = parts[1];

if (msg.type === "TLM" && parts.length >= 5) {
    msg.target = parts[2];
    msg.parameter = parts[3];
    msg.value = parts[4];
}
else if (msg.type === "ACK" && parts.length >= 4) {
    msg.target = parts[2];
    msg.value = parts[3];
}
else if (msg.type === "ERR" && parts.length >= 3) {
    msg.error = parts[2];

    if (parts.length >= 4) {
        msg.errorContext = parts[3];
        try {
            msg.errorContextDecoded = decodeURIComponent(parts[3]);
        } catch (err) {
            msg.errorContextDecoded = parts[3];
        }
    }
}

return msg;

let state = flow.get("satState") || {};
const receivedAtMs = Date.now();

if (!state.tlm) {
    state.tlm = {};
}
if (!state.lastAck) {
    state.lastAck = null;
}
if (!state.lastErr) {
    state.lastErr = null;
}
if (!state.time) {
    state.time = null;
}

if (msg.time) {
    state.time = msg.time;
}

if (msg.type === "TLM") {
    if (!msg.target || !msg.parameter) {
        return null;
    }

    if (!state.tlm[msg.target]) {
        state.tlm[msg.target] = {};
    }

    state.tlm[msg.target][msg.parameter] = {
        value: msg.value,
        time: msg.time,
        receivedAtMs
    };
}
else if (msg.type === "ACK") {
    state.lastAck = {
        target: msg.target || null,
        value: msg.value || null,
        time: msg.time || null,
        receivedAtMs
    };
}
else if (msg.type === "ERR") {
    state.lastErr = {
        error: msg.error || null,
        context: msg.errorContext || null,
        contextDecoded: msg.errorContextDecoded || null,
        time: msg.time || null,
        receivedAtMs
    };
}

flow.set("satState", state);

msg.state = state;
return msg;

let state = msg.state || flow.get("satState") || {};
const freshnessThresholdMs = 10000;

msg.payload = {
    time: state.time || "",
    freshnessThresholdMs,
    lastAck: state.lastAck || null,
    lastErr: state.lastErr || null,
    tlm: state.tlm || {},
    ackLog: (flow.get("ackLog") || []).slice(0, 12),
    errorLog: (flow.get("errorLog") || []).slice(0, 12),
    packetLog: (flow.get("packetLog") || []).slice(0, 58)
};

return msg;

let packetLog = flow.get("packetLog") || [];

packetLog.unshift({
    time: msg.time || "",
    receivedAtMs: Date.now(),
    packetType: msg.type || "",
    target: msg.target || "",
    parameter: msg.parameter || "",
    value: msg.value || msg.error || "",
    raw: msg.raw || ""
});

packetLog = packetLog.slice(0, 58);
flow.set("packetLog", packetLog);
return null;

if (msg.type !== "ERR") {
    return null;
}

let errorLog = flow.get("errorLog") || [];

errorLog.unshift({
    raw: msg.raw || ""
});

errorLog = errorLog.slice(0, 12);
flow.set("errorLog", errorLog);
return null;

if (msg.type !== "ACK") {
    return null;
}

let ackLog = flow.get("ackLog") || [];

ackLog.unshift({
    raw: msg.raw || ""
});

ackLog = ackLog.slice(0, 12);
flow.set("ackLog", ackLog);
return null;

const isClientConnect = msg.uibuilderCtrl === "client connect";
const isStateSyncRequest = msg.topic === "state-sync-request";
const isLogClearRequest = msg.topic === "log-clear-request";

if (!isClientConnect && !isStateSyncRequest && !isLogClearRequest) {
    return null;
}

return msg;

if (msg.topic !== "log-clear-request") {
    return msg;
}

const logName = String((msg.payload && msg.payload.log) || "");

if (logName === "ack") {
    flow.set("ackLog", []);
}
else if (logName === "error") {
    flow.set("errorLog", []);
}
else if (logName === "packet") {
    flow.set("packetLog", []);
}

return msg;

let state = flow.get("satState") || {};
const freshnessThresholdMs = 10000;

msg.topic = "state-sync";
msg.payload = {
    time: state.time || "",
    freshnessThresholdMs,
    lastAck: state.lastAck || null,
    lastErr: state.lastErr || null,
    tlm: state.tlm || {},
    ackLog: (flow.get("ackLog") || []).slice(0, 12),
    errorLog: (flow.get("errorLog") || []).slice(0, 12),
    packetLog: (flow.get("packetLog") || []).slice(0, 58)
};

return msg;
